19	const PROCESSING_FEE = 5;
20	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
21	
22	const BASE_PREMIUMS: Record<string, number> = {
23	  sword: 100,
24	  amulet: 60,
25	  staff: 80,
26	  potion: 40,
27	  rune: 25,
28	  moonstone: 25,
29	};
30	
31	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
32	const BLOCK_SIZE = 3;
33	const BLOCK_BASE_PREMIUM = 60;
34	
35	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
36	
37	const countByType = (items: Item[]): Record<string, number> => {
38	  const counts: Record<string, number> = {};
39	  for (const item of items) {
40	    counts[item.type] = (counts[item.type] ?? 0) + 1;
41	  }
42	  return counts;
43	};
44	
45	const componentGroupPremium = (type: string, count: number): number =>
46	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * BASE_PREMIUMS[type];
47	
48	const itemsBasePremium = (items: Item[]): number => {
49	  const mainItems = items.filter((item) => !isComponent(item));
50	  const components = items.filter(isComponent);
51	  const mainTotal = mainItems.reduce(
52	    (sum, item) => sum + BASE_PREMIUMS[item.type],
53	    0,
54	  );
55	  const componentTotal = Object.entries(countByType(components)).reduce(
56	    (sum, [type, count]) => sum + componentGroupPremium(type, count),
57	    0,
58	  );
59	  return mainTotal + componentTotal;
60	};
61	
62	const CURSE_SURCHARGE_RATE = 0.5;
63	
64	const itemSurcharge = (item: Item): number => {
65	  const base = BASE_PREMIUMS[item.type];
66	  return item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
67	};
68	
69	const quoteStep = (step: QuoteStep): QuoteResult => {
70	  const base = itemsBasePremium(step.items);
71	  const itemSurcharges = step.items.reduce((sum, item) => sum + itemSurcharge(item), 0);
72	  const withFirstContract = base + base * FIRST_CONTRACT_SURCHARGE_RATE;
73	  return { premium: Math.ceil(withFirstContract + itemSurcharges + PROCESSING_FEE) };
74	};
75	
76	export const runScenario = (scenario: Scenario): ScenarioResult => {
77	  return { results: scenario.steps.map(quoteStep) };
78	};
