const CURSE_SURCHARGE_RATE = 0.5;

const itemModifiersSurcharge = (item: Item): number => {
  const base = BASE_PREMIUMS[item.type];
  return item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
};

const sumItemModifiers = (items: Item[]): number =>
  items.reduce((sum, item) => sum + itemModifiersSurcharge(item), 0);

const policyModifiersSurcharge = (basePremium: number): number =>
  basePremium * FIRST_CONTRACT_SURCHARGE_RATE;

const quoteStep = (step: QuoteStep): QuoteResult => {
  const basePremium = itemsBasePremium(step.items);
  const itemModifiers = sumItemModifiers(step.items);
  const policyModifiers = policyModifiersSurcharge(basePremium);
  const premium = basePremium + itemModifiers + policyModifiers + PROCESSING_FEE;
  return { premium: Math.ceil(premium) };
};
